sub is_monotonic {
    my @nums = @_;

    return 1 if @nums <= 1;  # An array with 0 or 1 element is trivially monotonic

    my $increasing = 1;
    my $decreasing = 1;

    for my $i (0 .. $#nums - 1) {
        if ($nums[$i] > $nums[$i + 1]) {
            $increasing = 0;
        }
        if ($nums[$i] < $nums[$i + 1]) {
            $decreasing = 0;
        }
    }

    return $increasing || $decreasing;
